/* Reasoning GP — Articles data (batch 1: A–F)
   A–Z primary-care topic notes. Each: {id,title,category,icon,overview,features[],management[],referral[],source}
   Depth: written to the level an expert GP / RCGP examiner expects. */
(function(){
  const A = (window.RGP_ARTICLES = window.RGP_ARTICLES || []);
  A.push(

  { id:'bdd', title:'Body dysmorphic disorder (BDD)', category:'Mental health', icon:'🧠',
    overview:'A preoccupation with one or more perceived defects in appearance that are unnoticeable or only slight to others, driving time-consuming repetitive behaviours and marked distress or impairment. It sits on the OCD spectrum, is frequently missed for years, and carries one of the highest suicide rates in psychiatry.',
    features:[
      'Preoccupation with perceived flaw(s) — most often skin, hair, nose, but any body area; ≥1 hour/day of intrusive thinking',
      'Repetitive behaviours: mirror-checking or active mirror-avoidance, excessive grooming, skin-picking, camouflaging, reassurance-seeking, comparing with others',
      'Insight varies from fair to absent/delusional — poor insight does not exclude the diagnosis and predicts worse outcome',
      'Muscle dysmorphia variant (preoccupation with insufficient muscularity) — screen for anabolic steroid use',
      'Very high comorbidity: major depression (~75% lifetime), social anxiety, OCD, substance misuse, eating disorders',
      'Suicidality is the rule not the exception — ~80% suicidal ideation, high attempt rate; ask directly at every review',
      'Commonly presents covertly to dermatology, cosmetic and maxillofacial services rather than mental health — repeated dissatisfaction with procedures is a red flag'],
    management:[
      'Screen when suspicious (e.g. the BDD questionnaire / "Do you worry a lot about your appearance and wish you could think about it less?"); validate that the distress is real and the condition is recognised and treatable',
      'Assess severity, insight, functional impact and risk; document a suicide-risk assessment at every contact',
      'Mild: guided self-help based on CBT principles; signpost reputable resources',
      'Moderate–severe (NICE OCD/BDD): CBT specifically tailored to BDD (including exposure and response prevention) and/or an SSRI',
      'SSRIs need OCD-level dosing and patience — e.g. fluoxetine titrated to high dose, trial ≥12 weeks before judging response; continue ≥12 months if effective',
      'Combine CBT + SSRI for severe disease or where one modality is insufficient',
      'Actively discourage cosmetic, dermatological and surgical procedures — they rarely satisfy and often worsen preoccupation or shift it elsewhere',
      'Treat comorbid depression, anxiety and substance misuse; involve family/carers where appropriate; provide crisis/safety-netting information',
      'Review SSRI response at 4–6 weeks and again at 12 weeks — OCD-level doses take longer to work; if an adequate trial fails, switch to a second SSRI before specialist clomipramine',
      'Under-25s starting an SSRI: review within 1 week and warn about early agitation/akathisia and a transient rise in suicidal thoughts'],
    referral:[
      'Significant suicide or self-harm risk → same-day/urgent mental-health assessment (crisis team)',
      'Moderate–severe, delusional-intensity (absent insight), or refractory to first-line treatment → specialist mental-health / specialist OCD-BDD service',
      'Children and young people → CAMHS',
      'Requests for cosmetic procedures driven by BDD → decline and redirect to mental-health assessment'],
    source:'NICE CG31 (OCD/BDD) / NICE CKS' },

  { id:'bps', title:'Bladder pain syndrome (interstitial cystitis)', category:'Urology', icon:'💧',
    overview:'Persistent or recurrent pain perceived to relate to the bladder, accompanied by urinary urgency/frequency, in the absence of infection or other identifiable pathology. It is a clinical diagnosis of exclusion, frequently overlaps with other chronic pain syndromes, and is commoner in women.',
    features:[
      'Suprapubic/pelvic pain, pressure or discomfort that worsens with bladder filling and is typically relieved (at least transiently) by voiding',
      'Marked daytime frequency and nocturia, urgency; small voided volumes; symptoms ≥6 weeks (or recurrent) with sterile cultures',
      'Symptom flares with specific foods/drinks (caffeine, alcohol, acidic/spicy foods, artificial sweeteners), stress, menstruation, sexual activity',
      'Frequent overlap with IBS, fibromyalgia, chronic fatigue, vulvodynia, endometriosis and anxiety/depression',
      'Examination: suprapubic/pelvic-floor tenderness; assess for pelvic-floor muscle dysfunction',
      'Hunner lesions (a distinct phenotype seen at cystoscopy) respond to lesion-directed treatment — relevant when referring'],
    management:[
      'Exclude mimics first: MSU for infection, dipstick for blood; consider STI screen; review for malignancy (especially any visible haematuria), stones, and gynae causes',
      'Explain the diagnosis and chronic-pain model; set realistic expectations (control, not instant cure)',
      'Conservative first line: bladder diary, fluid optimisation, dietary triggers elimination-and-reintroduction, stress management, bladder retraining',
      'Pelvic-floor physiotherapy targeting muscle relaxation — avoid pelvic-floor strengthening (Kegels), which worsen hypertonic pelvic floor',
      'Pain: simple analgesia; consider amitriptyline (low dose, e.g. 10 mg nocte titrated) for pain, urgency and sleep; consider an antihistamine where relevant',
      'Manage comorbid IBS, mood and sleep; refer for psychological support if pain is dominant',
      'Specialist options after referral: bladder instillations, oral pentosan polysulfate, cystoscopy ± hydrodistension, treatment of Hunner lesions',
      'Trial bladder-directed self-care for ~3 months before referral — caffeine/trigger-food elimination, timed voiding and a bladder diary — and review response',
      'Amitriptyline: start 10 mg nocte, titrate to 25–50 mg as tolerated; review at 4–6 weeks; warn re drowsiness and anticholinergic effects'],
    referral:[
      'Visible haematuria, or unexplained non-visible haematuria with age/risk factors → urology 2WW to exclude bladder cancer',
      'Diagnostic uncertainty or symptoms refractory to conservative measures → urology / urogynaecology',
      'Severe pain limiting function or mental health → pain service / MDT'],
    source:'NICE CKS / EAU & RCOG guidance' },

  { id:'cervical-spondylosis', title:'Cervical spondylosis', category:'Musculoskeletal', icon:'🦴',
    overview:'Age-related degenerative change of the cervical spine (disc, facet and osteophyte) causing axial neck pain and stiffness. Most is benign and self-limiting, but it can produce radiculopathy (nerve-root compression) or, less commonly, myelopathy (spinal-cord compression) — the key not-to-miss complication.',
    features:[
      'Axial neck pain/stiffness, occipital or referred shoulder-girdle pain, crepitus, reduced range of movement; common over 40',
      'Cervicogenic headache; symptoms often worse with sustained postures',
      'Radiculopathy: dermatomal arm pain, paraesthesia and/or myotomal weakness; reproduced by Spurling test; C6 and C7 roots most affected',
      'Myelopathy (RED FLAG): progressive gait disturbance/imbalance, clumsy hands, loss of dexterity (buttons, handwriting), urinary urgency',
      'Myelopathic signs: brisk reflexes, up-going plantars, positive Hoffmann sign, Lhermitte phenomenon, inverted supinator reflex',
      'Consider alternative serious causes if pain is non-mechanical, nocturnal, with systemic features or in those with cancer history'],
    management:[
      'Reassure: uncomplicated mechanical neck pain is usually self-limiting; encourage staying active and maintaining movement',
      'Analgesia: paracetamol and/or NSAID (with gastroprotection where indicated); short-term consider topical NSAID; avoid long-term opioids',
      'Encourage range-of-movement and strengthening exercises; physiotherapy for persistent symptoms; address posture and workstation ergonomics',
      'Do not image uncomplicated neck pain; reserve MRI for radiculopathy not settling, suspected myelopathy, or red flags',
      'Neuropathic adjuncts (e.g. amitriptyline) may help radicular pain; most radiculopathy improves conservatively over weeks–months',
      'Address yellow flags (fear-avoidance, low mood) that predict chronicity',
      'Safety-net explicitly: urgent review for new limb weakness, clumsy hands, gait/balance change or bladder symptoms (cord myelopathy)',
      'Review at 4–6 weeks; if radicular pain persists, trial amitriptyline 10 mg nocte (or duloxetine 30→60 mg) and refer physiotherapy'],
    referral:[
      'Any signs/symptoms of cervical myelopathy → urgent spinal/neurosurgical referral and MRI — do not delay (delay risks irreversible cord injury)',
      'Progressive or severe neurological deficit → urgent',
      'Radiculopathy persisting/disabling beyond ~6 weeks despite conservative care → spinal/MSK service',
      'Red flags for malignancy/infection (systemic upset, night pain, immunosuppression, IVDU) → urgent investigation'],
    source:'NICE CKS — Neck pain (cervical radiculopathy / non-specific)' },

  { id:'me-cfs', title:'Chronic fatigue syndrome (ME/CFS)', category:'Neurology', icon:'🛌',
    overview:'A chronic, disabling, multi-system condition defined by debilitating fatigue, post-exertional malaise, unrefreshing sleep and cognitive dysfunction, persisting ≥3 months and not explained by another condition. NG206 (2021) reframed management — graded exercise therapy as a fixed cure is no longer recommended.',
    features:[
      'Debilitating fatigue, new and persistent, not relieved by rest and not the result of ongoing exertion',
      'Post-exertional malaise (PEM): disproportionate worsening of symptoms after activity, often delayed by hours–days and prolonged ("push–crash")',
      'Unrefreshing or disturbed sleep; cognitive difficulties ("brain fog") — memory, concentration, word-finding',
      'Frequent orthostatic intolerance/PoTS, pain, temperature dysregulation, sensory sensitivities; symptoms fluctuate day-to-day',
      'Diagnosis is clinical: all four core features for ≥3 months in adults, after a sensible screen excludes mimics',
      'Baseline exclusion bloods: FBC, U&E, LFT, TFT, ESR/CRP, glucose/HbA1c, calcium, CK, ferritin, coeliac serology, ± vitamin D — guided by history',
      'Note diagnostic overlap and comorbidity with depression, fibromyalgia and PoTS; ME/CFS can coexist with these'],
    management:[
      'Believe and validate; explicitly avoid "just exercise / push through" advice — fixed incremental GET is no longer recommended (NG206)',
      'Energy management / pacing: help the person stay within their individual energy envelope to avoid PEM; flexible activity, not fixed escalation',
      'Develop a personalised, collaborative care and support plan; review regularly; provide adjustments for work/education (and a Fit Note where needed)',
      'Manage symptoms individually: sleep hygiene, pain, orthostatic intolerance (fluids/salt, manage PoTS), and comorbid mood',
      'Refer to a specialist ME/CFS service to confirm diagnosis and guide management, ideally within the first months',
      'Be alert to deconditioning vs PEM; physiotherapy only within a pacing framework by clinicians who understand ME/CFS',
      'Safeguard severe/very severe patients (housebound/bedbound) — proactive review, nutrition, pressure care, home-based input',
      'Confirm the exclusion screen (FBC, U&E, LFT, TFT, ESR/CRP, HbA1c, calcium, CK, ferritin, coeliac serology, vitamin D) is normal before diagnosis — then avoid over-investigation',
      'Review every few months; issue a Fit Note and work/education adjustments; manage orthostatic intolerance (fluids, added salt, compression) and sleep specifically'],
    referral:[
      'Refer to a specialist ME/CFS service to confirm the diagnosis and direct management (per NG206)',
      'Severe or very severe disease (housebound/bedbound) → specialist + community/social support and safeguarding consideration',
      'Diagnostic uncertainty, red flags, or atypical features → relevant specialty to exclude alternative pathology',
      'Children and young people → paediatric ME/CFS specialist'],
    source:'NICE NG206' },

  { id:'crps', title:'Complex regional pain syndrome (CRPS)', category:'Neurology', icon:'🔥',
    overview:'Chronic regional pain — usually in a limb and disproportionate to any inciting event (commonly after fracture, surgery or minor trauma) — with sensory, vasomotor, sudomotor/oedema and motor/trophic changes. Outcomes are time-dependent, so early recognition and referral matter.',
    features:[
      'Continuing pain disproportionate to the inciting event; burning quality; allodynia and hyperalgesia',
      'Vasomotor changes: skin colour and temperature asymmetry between limbs',
      'Sudomotor/oedema: swelling and sweating asymmetry',
      'Motor/trophic: reduced range of movement, weakness, tremor/dystonia; changes in skin, nail and hair growth',
      'Diagnosis is clinical using the Budapest criteria (symptoms in ≥3 categories + signs in ≥2, with no better explanation)',
      'CRPS type I (no nerve lesion) vs type II (associated peripheral nerve injury)'],
    management:[
      'Recognise early — outcomes are better with prompt treatment and referral',
      'Encourage normal use of the limb and avoid immobilisation; refer for physiotherapy/OT (graded motor imagery, desensitisation, mirror therapy)',
      'Neuropathic analgesia per NICE NG affecting choice (amitriptyline, duloxetine, gabapentin or pregabalin); short courses of other agents as guided',
      'Treat associated mood, sleep disturbance and fear-avoidance; provide education and self-management support',
      'Set function-focused goals rather than pain-elimination goals',
      'Vitamin C after wrist fracture has been used for prophylaxis in some settings (local guidance)',
      'Neuropathic-agent doses: amitriptyline 10 mg nocte titrated, duloxetine 30→60 mg, or gabapentin/pregabalin titrated; review at 4–6 weeks',
      'Refer to the pain service within weeks, not months — early multidisciplinary input is the main predictor of recovery'],
    referral:[
      'Refer early to a pain service / specialist MDT — do not wait for symptoms to entrench',
      'Suspected CRPS after fracture or cast (e.g. pain disproportionate to injury, tight cast symptoms) → orthopaedics/pain',
      'Refractory, spreading or severely disabling symptoms → specialist pain MDT',
      'Diagnostic doubt or atypical neurology → neurology'],
    source:'Royal College of Physicians CRPS guidance / NICE CKS' },

  { id:'cvs', title:'Cyclical vomiting syndrome', category:'Gastroenterology', icon:'🤢',
    overview:'Recurrent, stereotyped episodes of intense nausea and vomiting separated by symptom-free intervals. Commoner in children but increasingly recognised in adults, it is strongly associated with migraine and, in adults, with chronic cannabis use (cannabinoid hyperemesis, an important mimic).',
    features:[
      'Discrete, stereotyped episodes of severe vomiting, similar in onset, duration and symptoms each time, with complete wellness between',
      'Often a prodrome (nausea, pallor, lethargy) and identifiable triggers: stress/excitement, infection, fasting, menstruation, poor sleep',
      'Strong personal or family history of migraine; episodes may evolve into migraine over time',
      'Risk of dehydration, electrolyte disturbance and metabolic alkalosis during attacks',
      'Adults: ask specifically about cannabis — cannabinoid hyperemesis classically relieved by hot baths/showers',
      'Diagnosis is clinical after excluding GI obstruction, metabolic disease, raised intracranial pressure and Addison disease'],
    management:[
      'Identify and avoid triggers; provide a written individualised action plan and reassurance',
      'Acute attack: rest in a dark, quiet room; rehydrate (oral or IV if needed); antiemetics (e.g. ondansetron); treat as a migraine variant with triptan ± analgesia where appropriate',
      'Correct dehydration and electrolytes; consider admission for IV fluids if not tolerating oral intake',
      'Prophylaxis for frequent/severe episodes (specialist-guided): migraine prophylactics such as amitriptyline, propranolol or topiramate (pizotifen in children)',
      'Address cannabis use directly — cessation is curative in cannabinoid hyperemesis',
      'Support sleep, stress management and regular meals to reduce triggers',
      'Acute: ondansetron 4–8 mg; if migrainous, add a triptan in the prodrome; safety-net to attend if unable to keep fluids down (dehydration/electrolytes)',
      'Prophylaxis (specialist-guided) for frequent/severe episodes: amitriptyline or propranolol in adults, pizotifen in children — review benefit over 2–3 months'],
    referral:[
      'Dehydration/electrolyte disturbance not manageable at home, or unable to keep fluids down → admit',
      'Red flags — abnormal neuro exam, severe abdominal pain, bilious vomiting, weight loss, or diagnostic uncertainty → paediatrics/gastroenterology (imaging to exclude obstruction/ICP)',
      'Frequent or refractory episodes needing prophylaxis → gastroenterology/neurology',
      'Children with first presentation or atypical features → paediatric assessment'],
    source:'NICE CKS / BSPGHAN & Rome IV criteria' },

  { id:'dementia-subtypes', title:'Dementia subtypes (Alzheimer\u2019s, vascular, Lewy body, frontotemporal)', category:'Neurology', icon:'🧠',
    overview:'The four common dementia syndromes differ in presentation, trajectory and — crucially — in safe prescribing. Recognising the subtype guides treatment choice and avoids harm, above all the severe antipsychotic sensitivity of Lewy body dementia.',
    features:[
      'Alzheimer\u2019s (commonest): insidious episodic memory loss, disorientation, word-finding and visuospatial decline; gradual progression',
      'Vascular: stepwise or patchy decline, prominent executive/processing-speed impairment, focal neurology, vascular risk factors; often mixed with AD',
      'Lewy body (DLB): fluctuating cognition and attention, recurrent well-formed visual hallucinations, spontaneous parkinsonism, REM-sleep behaviour disorder, marked antipsychotic sensitivity, autonomic features and falls',
      'Frontotemporal (FTD): early change in personality/behaviour (disinhibition, apathy, loss of empathy) or progressive language impairment; younger onset (often 50s–60s); memory relatively preserved early',
      'Always exclude reversible/contributing causes: depression (pseudodementia), hypothyroidism, B12/folate deficiency, delirium, medication (anticholinergic burden), alcohol',
      'Sudden or rapidly progressive cognitive decline is atypical and needs urgent work-up (e.g. prion disease, autoimmune encephalitis)'],
    management:[
      'Refer to memory assessment service for diagnosis and subtyping; treat reversible contributors and optimise sensory impairment',
      'Acetylcholinesterase inhibitors (donepezil, rivastigmine, galantamine) for mild–moderate Alzheimer\u2019s and for DLB (also help DLB hallucinations); memantine for moderate–severe AD or if AChEIs not tolerated',
      'Vascular dementia: optimise vascular risk factors (BP, lipids, diabetes, antiplatelet, smoking); cognitive enhancers not routinely indicated unless mixed AD',
      'DLB: AVOID antipsychotics where possible (risk of severe sensitivity reactions, irreversible parkinsonism, neuroleptic malignant syndrome); rivastigmine for cognition/hallucinations; treat RBD and orthostatic hypotension',
      'Minimise anticholinergic burden across all subtypes; review and deprescribe culprit drugs',
      'Manage BPSD non-pharmacologically first; reserve low-dose antipsychotics for severe distress/risk, time-limited, with documented discussion of stroke/mortality risk (and never first in DLB)',
      'Post-diagnostic support: carer assessment and support, advance care planning, LPA discussion, DVLA notification (patient\u2019s duty), and safeguarding awareness',
      'Before referral do the reversible-cause screen: bloods (FBC, U&E, LFT, TFT, B12/folate, calcium, HbA1c), medication/anticholinergic review and a mood screen',
      'Donepezil: start 5 mg → 10 mg at 4 weeks (check pulse/ECG if bradycardia risk); warn re GI effects; review cognition, function and drug benefit at least annually'],
    referral:[
      'All suspected dementia → memory assessment service for diagnosis and subtype',
      'Young-onset (<65), rapidly progressive, or atypical presentation → neurology/specialist',
      'Severe behavioural and psychological symptoms or risk → old-age psychiatry/community mental-health team',
      'Suspected DLB needing symptom control, or any antipsychotic decision in DLB → specialist'],
    source:'NICE NG97' },

  { id:'dengue', title:'Dengue fever', category:'Infectious diseases', icon:'🦟',
    overview:'A mosquito-borne flavivirus infection in travellers returning from endemic areas (Asia, Latin America, Africa). Most is self-limiting, but a minority progress to severe dengue (plasma leakage, haemorrhage, shock) around defervescence — the critical window to recognise.',
    features:[
      'High fever, severe frontal/retro-orbital headache, myalgia and arthralgia ("breakbone fever"), nausea, and a maculopapular rash',
      'Onset typically within 14 days of return from an endemic area (incubation 4–10 days) — fever beyond 14 days makes dengue unlikely',
      'Warning signs of severe dengue (around day 3–7 as fever settles): abdominal pain/tenderness, persistent vomiting, mucosal bleeding, lethargy/restlessness, hepatomegaly, and a rising haematocrit with rapidly falling platelets',
      'Bloods: leukopenia, thrombocytopenia, raised haematocrit (haemoconcentration), transaminitis',
      'Always exclude malaria in any febrile returning traveller (and consider enteric fever, rickettsia, other arboviruses)',
      'Notifiable disease; diagnosis confirmed by NS1 antigen and/or serology/PCR'],
    management:[
      'In a febrile returning traveller, exclude malaria urgently (thick and thin films/RDT) before attributing fever to dengue',
      'Supportive care: maintain oral hydration, rest, and paracetamol for fever/pain',
      'AVOID NSAIDs and aspirin (bleeding risk and gastritis); avoid IM injections',
      'Most cases are managed supportively at home with clear safety-netting; arrange review and FBC monitoring where access allows',
      'Recognise the critical phase around defervescence — monitor platelets/haematocrit and warning signs',
      'Notify and discuss with infectious diseases / tropical medicine; advise mosquito-bite avoidance to limit transmission',
      'Antipyretic: paracetamol only (max 1 g QDS); reiterate no NSAIDs/aspirin and no IM injections',
      'Give the warning-sign list and arrange an FBC around days 3–7 (defervescence) — the critical phase for plasma leakage'],
    referral:[
      'Any warning signs of severe dengue, bleeding, or haemodynamic compromise → urgent hospital admission',
      'All febrile returning travellers → exclude malaria urgently; discuss with infectious diseases',
      'Pregnancy, significant comorbidity, or extremes of age → lower threshold to admit',
      'Diagnostic uncertainty in an unwell traveller → infectious diseases/tropical medicine'],
    source:'UKHSA / NICE CKS — Fever in returning travellers' },

  { id:'eds', title:'Ehlers-Danlos syndromes (EDS)', category:'Musculoskeletal', icon:'🧬',
    overview:'A group of heritable connective-tissue disorders causing joint hypermobility, skin hyperextensibility and tissue fragility. Hypermobile EDS (hEDS) is the type usually seen in primary care; the rare vascular type (vEDS) is the dangerous one because of catastrophic arterial, bowel and uterine rupture.',
    features:[
      'Generalised joint hypermobility (Beighton score), recurrent subluxations/dislocations, chronic widespread musculoskeletal pain and early osteoarthritis',
      'Skin: soft, mildly hyperextensible, easy bruising, atrophic scarring, delayed wound healing',
      'Systemic associations: fatigue, autonomic dysfunction (PoTS), GI dysmotility (reflux, bloating, constipation), pelvic-floor and bladder symptoms, anxiety',
      'Vascular EDS (rare, high concern): thin translucent skin with visible veins, easy bruising, characteristic facies, and risk of arterial/intestinal/uterine rupture — often a family history of sudden death',
      'Classical EDS: marked skin hyperextensibility and atrophic scarring; other rarer subtypes have specific features',
      'hEDS diagnosis is clinical (2017 criteria); most other subtypes have a molecular/genetic basis'],
    management:[
      'hEDS is largely a clinical diagnosis managed with supportive, multidisciplinary care; explain the condition and set realistic expectations',
      'Physiotherapy is the cornerstone: joint stabilisation, paced low-impact strengthening, proprioceptive work; occupational therapy and joint protection/orthoses',
      'Pain management following chronic-pain principles; avoid escalating opioids; address sleep and mood',
      'Manage associated PoTS (fluids, salt, compression, graded exercise), GI symptoms, and pelvic-floor dysfunction',
      'Support pacing, activity modification, education and patient resources; consider bone health',
      'Pre-procedure caution: warn surgeons/anaesthetists about tissue fragility, poor wound healing and local-anaesthetic considerations',
      'Actively screen for vascular-EDS red flags (family history of sudden death/arterial events) and arrange echocardiography if aortic-root concern',
      'Primary-care bundle: refer physiotherapy, give joint-protection/pacing advice, and manage PoTS (fluids/salt/compression), reflux and constipation'],
    referral:[
      'Any suspicion of vascular EDS (or other rare subtype, or significant family history) → clinical genetics — urgent if vascular features (and avoid arteriography/invasive vascular procedures where possible)',
      'Aortic root dilatation or cardiac concern → cardiology with echocardiography',
      'Complex or refractory pain/instability → rheumatology / pain / specialist MDT',
      'Significant autonomic or GI dysfunction → relevant specialist'],
    source:'NICE CKS / 2017 international EDS classification' },

  { id:'febrile-seizures', title:'Febrile seizures', category:'Paediatrics', icon:'🌡️',
    overview:'Seizures occurring with fever in children (typically 6 months–5 years) without CNS infection, metabolic cause or a history of afebrile seizures. They are common (2–5% of children) and usually benign — the main jobs are excluding serious infection and supporting frightened parents.',
    features:[
      'Simple (most): generalised tonic-clonic, lasting <15 minutes, a single seizure within 24 hours, with full recovery',
      'Complex: focal onset, prolonged (>15 minutes), or recurrent within the same febrile illness/24 hours',
      'Febrile status epilepticus: a febrile seizure lasting ≥30 minutes',
      'Recurrence risk ~30% overall (higher with younger age at onset, lower fever at onset, family history, short fever-to-seizure interval)',
      'Risk of later epilepsy slightly raised — close to background after a simple seizure, higher after complex/prolonged or with neurodevelopmental concerns/family history',
      'Always assess for the source of fever and exclude meningitis/encephalitis (especially if <18 months, where signs are subtle)'],
    management:[
      'Reassure parents that simple febrile seizures are common and benign and do not cause brain damage',
      'Antipyretics improve comfort but do NOT prevent recurrence — say so explicitly to avoid over-treatment of fever',
      'First-aid advice: stay calm, protect from injury, place in the recovery position, do not put anything in the mouth, and time the seizure',
      'Safety-net clearly: call 999 if a seizure lasts >5 minutes, repeats, or the child is hard to rouse/looks seriously unwell',
      'For recurrent prolonged seizures, a specialist may provide a rescue plan (buccal midazolam) with training',
      'Identify and treat the underlying infection appropriately; routine investigations (EEG, imaging, bloods) are not needed for simple febrile seizures',
      'Document it was a SIMPLE febrile seizure (generalised, <15 min, single in 24 h, full recovery) — this is what makes safe community management appropriate',
      'Give written first-aid + 999 advice and reassure about the ~30% recurrence risk and near-background later-epilepsy risk'],
    referral:[
      'Seizure lasting >5 minutes, repeated seizures, or a child who appears seriously unwell → 999/emergency',
      'First febrile seizure, any complex features, age <18 months, or diagnostic doubt → same-day paediatric assessment',
      'Suspected meningitis/encephalitis → emergency admission and empirical treatment',
      'Recurrent febrile seizures or parental anxiety needing a rescue plan → paediatrics'],
    source:'NICE CKS — Febrile seizure' },

  { id:'fgm', title:'Female genital mutilation (FGM)', category:'Women\u2019s health', icon:'🛡️',
    overview:'All procedures involving partial or total removal of the external female genitalia, or other injury to the female genital organs, for non-medical reasons. It is illegal in the UK, a form of child abuse and gender-based violence, and carries specific mandatory reporting and recording duties for clinicians.',
    features:[
      'Classified WHO types I–IV (clitoridectomy, excision, infibulation, and other procedures including pricking/cauterisation)',
      'May present with urinary problems (obstruction, recurrent UTI), dysmenorrhoea, apareunia/dyspareunia, recurrent infections, keloid/cysts, or be identified at cervical screening, antenatal booking or examination',
      'Psychological sequelae are common: PTSD, anxiety, depression, sexual difficulties',
      'Risk indicators: family from a practising community, planned travel abroad ("cutting season"), an older sibling affected, references to a "special procedure"',
      'Type III (infibulation) may cause obstructed labour and need antenatal de-infibulation planning'],
    management:[
      'Approach sensitively and non-judgementally; use a professional interpreter (never a family member)',
      'Know and act on legal duties: the mandatory reporting duty requires reporting known cases in a girl under 18 to the police (101); record FGM in the records; complete FGM Enhanced Dataset returns',
      'Undertake a safeguarding risk assessment for the patient and for siblings/other girls in the family; girls at risk → children\u2019s social care/safeguarding lead',
      'Document type, complications and discussions; provide information that re-infibulation and performing FGM are illegal',
      'Refer for de-infibulation and to specialist FGM services; in pregnancy, plan antenatal/intrapartum care',
      'Address physical complications and psychological consequences; involve the GP safeguarding lead',
      'Know the practical steps: report known FGM in a girl under 18 to police on 101, complete the FGM Enhanced Dataset, and assess risk to siblings — document fully'],
    referral:[
      'Known FGM in a girl under 18 → mandatory police report + safeguarding referral',
      'Any girl assessed as at risk of FGM → children\u2019s social care / safeguarding (urgent if travel imminent)',
      'Physical complications, type III, or pregnancy → specialist FGM clinic / obstetrics & gynaecology',
      'Significant psychological impact → mental-health services'],
    source:'GOV.UK FGM mandatory reporting / RCOG / safeguarding guidance' },

  { id:'fasd', title:'Fetal alcohol spectrum disorder (FASD)', category:'Paediatrics', icon:'🍼',
    overview:'A range of lifelong neurodevelopmental and physical effects caused by prenatal alcohol exposure. It is common but under-recognised; early identification and support improve outcomes, and prevention rests on clear advice that no level of alcohol in pregnancy is known to be safe.',
    features:[
      'Neurodevelopmental: cognitive and learning difficulties, executive dysfunction, poor impulse control, ADHD-like presentation, language and memory problems',
      'Sentinel facial features (in fetal alcohol syndrome): short palpebral fissures, smooth philtrum, thin upper lip (most are without the full facial phenotype)',
      'Pre/postnatal growth restriction',
      'Behavioural, emotional and social difficulties; sleep problems; increased risk of secondary difficulties (school exclusion, offending, mental health) without support',
      'A history of prenatal alcohol exposure supports the diagnosis but is often uncertain or unavailable (e.g. in looked-after/adopted children)'],
    management:[
      'Recognise and refer for multidisciplinary neurodevelopmental assessment; diagnosis enables support and adjustments',
      'Coordinate education support (EHCP where needed), behavioural and developmental interventions, and family/carer support',
      'Manage comorbidities — ADHD, sleep disturbance, anxiety/mood — with the relevant pathways',
      'Provide structure, routine and environmental adaptation; signpost FASD support organisations',
      'Prevention: give clear advice that no amount of alcohol is known to be safe in pregnancy or when trying to conceive; offer support to reduce alcohol use in current/future pregnancies',
      'Be alert to safeguarding and the needs of looked-after children',
      'Coordinate via the relevant pathways: ADHD (paediatrics/CAMHS), sleep (hygiene ± specialist melatonin), anxiety/low mood, plus EHCP and carer support'],
    referral:[
      'Suspected FASD or neurodevelopmental concern → paediatrics / neurodevelopmental pathway',
      'Learning and behavioural difficulties → educational psychology and developmental services',
      'Comorbid ADHD/mental-health needs → CAMHS/paediatrics',
      'Safeguarding concerns → children\u2019s social care'],
    source:'SIGN 156 / NICE quality standard on FASD' },

  { id:'food-allergy-intolerance', title:'Food allergy and intolerance', category:'Allergy & immunology', icon:'🥜',
    overview:'Food allergy is an immune-mediated reaction (IgE-mediated or non-IgE-mediated); food intolerance is non-immune (e.g. enzymatic, pharmacological). Distinguishing them — chiefly through an allergy-focused history — directs appropriate testing and avoids both under- and over-investigation.',
    features:[
      'IgE-mediated: rapid onset (minutes–2 hours) — urticaria, angioedema, vomiting, abdominal pain, wheeze, and potentially anaphylaxis; reproducible with the trigger',
      'Non-IgE-mediated: delayed (hours–days) — GI symptoms, eczema flares, reflux, blood/mucus in stool; classic example cow\u2019s-milk protein allergy in infants',
      'Food intolerance: dose-related, non-immune symptoms, usually GI, no risk of anaphylaxis (e.g. lactose intolerance, caffeine)',
      'Common IgE allergens: peanut, tree nuts, milk, egg, fish, shellfish, wheat, soya, sesame',
      'An allergy-focused clinical history is the cornerstone — timing, reproducibility, quantity, cofactors (exercise, NSAIDs, alcohol)',
      'Risk-stratify for anaphylaxis: previous severe reaction, asthma (especially poorly controlled), nut/shellfish triggers'],
    management:[
      'Take an allergy-focused history; arrange specific IgE blood tests or skin-prick testing only when the history suggests IgE-mediated allergy (test to the suspected food, not broad panels)',
      'Identify and avoid the confirmed trigger; provide dietitian input for exclusion diets, label-reading and nutritional adequacy (especially in children)',
      'For anaphylaxis risk: prescribe two adrenaline auto-injectors, train the patient/carers, provide a personalised emergency action plan, and ensure asthma is optimally controlled',
      'Treat acute non-severe reactions with antihistamine; treat anaphylaxis with IM adrenaline and emergency care',
      'For suspected cow\u2019s-milk protein allergy in infants, follow the iMAP pathway (maternal dietary exclusion if breastfed, or extensively hydrolysed formula)',
      'Do NOT use unvalidated tests (food-specific IgG, hair analysis, kinesiology, VEGA) — they are not recommended and mislead',
      'For anaphylaxis risk: prescribe TWO adrenaline auto-injectors by brand, train technique, give a written action plan, and renew before expiry/after any reaction',
      'Optimise asthma — the leading risk factor for fatal anaphylaxis — checking inhaler technique and adherence'],
    referral:[
      'Anaphylaxis or any severe systemic reaction → emergency treatment + referral to a specialist allergy clinic',
      'Suspected IgE-mediated food allergy, multiple or unclear triggers, or diagnostic uncertainty → allergy clinic',
      'Faltering growth, complex exclusion diets, or multiple food allergies (especially in children) → paediatric allergy/dietetics',
      'Consideration of oral food challenge or component testing → specialist'],
    source:'NICE CG116 (food allergy in children/young people) / NICE CKS' },

  { id:'frostbite', title:'Frostbite', category:'Dermatology', icon:'❄️',
    overview:'A freezing injury of tissues, usually affecting the extremities (fingers, toes, ears, nose, cheeks), with severity ranging from superficial frostnip to deep tissue loss. It commonly coexists with hypothermia, which is the priority, and early specialist treatment can salvage tissue.',
    features:[
      'Early: numbness, pins-and-needles, and pale, white or waxy skin; the part may feel hard or frozen in deep injury',
      'On rewarming: significant pain, erythema, swelling and blistering — clear blisters suggest superficial injury and a better prognosis; haemorrhagic blisters suggest deeper damage',
      'Deep frostbite: persistent numbness, non-blanching mottling, and eventual demarcation/eschar over days–weeks',
      'Risk factors: prolonged cold/wind/wet exposure, alcohol and drug use, homelessness, smoking, peripheral vascular disease, inadequate clothing, altitude',
      'Frequently associated with hypothermia and other cold injuries (treat hypothermia first)'],
    management:[
      'Treat hypothermia and any life-threatening problems first; move the person somewhere warm and remove wet/constrictive clothing and jewellery',
      'Rapid rewarming by immersion in warm water (37–39°C) for ~15–30 minutes — only if there is NO risk of refreezing (refreeze–thaw cycles greatly worsen injury)',
      'Do NOT rub or massage the affected part, and do not use direct dry heat (fire, radiator)',
      'Provide strong analgesia (rewarming is very painful) and consider ibuprofen for its anti-inflammatory effect',
      'Elevate the limb, apply loose non-adherent dressings, separate affected digits, do not deliberately deroof blisters, and check tetanus status',
      'Avoid alcohol and nicotine (vasoconstriction); arrange specialist assessment for anything beyond minor frostnip',
      'Analgesia: strong opioid for rewarming pain plus ibuprofen 400 mg TDS; check/boost tetanus; photograph and document to track demarcation over days–weeks'],
    referral:[
      'Deep frostbite, significant or haemorrhagic blistering, or any diagnostic doubt → emergency/specialist (early thrombolysis or iloprost within a tight time window may salvage tissue)',
      'Coexisting hypothermia or systemic illness → emergency admission',
      'Involvement of face/large areas, or vulnerable patient → low threshold for admission',
      'Homelessness or recurrent cold exposure → social support and safeguarding'],
    source:'NICE CKS / wilderness & cold-injury guidance' },

  { id:'fnd', title:'Functional neurological disorder (FND)', category:'Neurology', icon:'🧠',
    overview:'Genuine, often disabling neurological symptoms — limb weakness, sensory disturbance, dissociative (non-epileptic) seizures, movement disorders, persistent dizziness — that arise from a problem with nervous-system functioning rather than structural disease. It is diagnosed positively on examination, not merely by exclusion.',
    features:[
      'Positive clinical signs are key: Hoover sign and hip-abductor sign for functional leg weakness; tremor entrainment/distractibility; give-way (collapsing) weakness; inconsistency and variability over time',
      'Symptoms are real and involuntary — not feigned; distinguishing from factitious disorder and malingering',
      'Common presentations: functional limb weakness, dissociative (non-epileptic) attacks, functional tremor/dystonia, functional gait disorder, persistent postural-perceptual dizziness',
      'Frequent triggers/associations: physical injury or illness, panic at onset, anxiety, depression, chronic pain, and prior adverse experiences (not universal)',
      'Dissociative seizures: often longer duration, eyes closed/resisting opening, fluctuating course, recall variable, no post-ictal confusion or significant injury pattern of epilepsy'],
    management:[
      'Make and clearly communicate a positive diagnosis — explain it is common, recognised, and potentially reversible; how the signs (e.g. Hoover) demonstrate it; that symptoms are real',
      'Avoid repeated unnecessary investigations once the diagnosis is secure — over-investigation reinforces illness behaviour',
      'Refer for multidisciplinary rehabilitation: FND-trained physiotherapy (for motor symptoms), psychology/CBT, and occupational therapy',
      'Treat comorbid anxiety, depression and pain; consider an SSRI/SNRI where indicated',
      'Signpost reputable patient resources (neurosymptoms.org); engage the patient as an active partner',
      'For dissociative seizures, provide a management plan and psychological therapy; avoid antiepileptic drugs unless epilepsy coexists',
      'Record the positive diagnosis and explanation in the notes and to the patient, avoid repeat scans, and refer FND-trained physiotherapy + psychology early',
      'Track function and therapy engagement rather than symptom counts; treat comorbid anxiety, depression and sleep'],
    referral:[
      'New, progressive, or red-flag neurology / diagnostic uncertainty → neurology to confirm the diagnosis',
      'Confirmed FND → specialist neuro-rehabilitation / FND service (physiotherapy + psychology)',
      'Dissociative (non-epileptic) seizures → neurology/psychology pathway',
      'Significant comorbid mental-health needs or risk → mental-health services'],
    source:'NICE CKS / FND clinical guidance (neurosymptoms.org)' },

  { id:'adhd', title:'Attention deficit hyperactivity disorder (ADHD)', category:'Mental health', icon:'🧠',
    overview:'A childhood-onset neurodevelopmental disorder of persistent inattention, hyperactivity and impulsivity that impairs function across more than one setting (home, school, work). Symptoms persist into adulthood in around two-thirds; it is widely under-recognised in girls (more inattentive, less disruptive) and in adults.',
    features:[
      'Inattention: careless mistakes, poor sustained attention, not listening, unfinished tasks, disorganisation, losing things, distractibility, forgetfulness',
      'Hyperactivity/impulsivity: fidgeting, leaving seat, restlessness, talking excessively, blurting out, interrupting, impatience',
      'Onset before age 12, present in ≥2 settings, with clear functional impairment — not better explained by another condition',
      'Adults often present with disorganisation, procrastination, emotional dysregulation, relationship/employment difficulties or a child’s recent diagnosis',
      'High comorbidity: anxiety, depression, substance misuse, sleep disorder, autism spectrum, tics, learning difficulties',
      'Driving, occupational and forensic risks; screen for substance misuse before stimulant initiation'],
    management:[
      'Primary-care role is recognition, initial functional/risk assessment and referral — ADHD is a specialist diagnosis (it cannot be diagnosed or first-line medicated in primary care)',
      'Offer information, signpost support groups, and give practical environmental strategies (routines, lists, reminders) while awaiting assessment',
      'Drug treatment (specialist-initiated) is reserved for moderate–severe impairment: first-line stimulants — methylphenidate (children) or lisdexamfetamine/methylphenidate (adults); non-stimulant atomoxetine or guanfacine as alternatives',
      'Shared-care monitoring once stable: height and weight plotted (children), pulse and blood pressure each dose change then 6-monthly, appetite/sleep, mood and tics',
      'Baseline cardiovascular check before stimulants; refer for cardiology opinion if a personal/family history of cardiac disease',
      'Treat comorbid anxiety, depression and sleep problems; address substance misuse',
      'Annual review of the continued need for medication, including planned trials off treatment where appropriate'],
    referral:[
      'Suspected ADHD with significant impairment → specialist (community paediatrics/CAMHS for under-18s; adult ADHD service)',
      'Diagnostic uncertainty, complex comorbidity (autism, intellectual disability) or significant risk → specialist',
      'Cardiac history before/at stimulant initiation → cardiology',
      'Breakdown of shared-care arrangement or adverse effects → re-refer to the initiating specialist'],
    source:'NICE NG87' },

  { id:'bipolar-lithium', title:'Bipolar disorder and lithium monitoring', category:'Mental health', icon:'🧠',
    overview:'A recurrent mood disorder with episodes of mania/hypomania and depression. Lithium remains the most effective long-term mood stabiliser but has a narrow therapeutic index, making safe primary-care monitoring and interaction-awareness essential.',
    features:[
      'Mania: elevated/irritable mood, reduced need for sleep, grandiosity, pressured speech, racing thoughts, risk-taking, psychosis — impairs function (hypomania is milder, ≥4 days, no psychosis)',
      'Bipolar depression: as for unipolar but antidepressant monotherapy risks switching to mania',
      'Lithium therapeutic range 0.4–1.0 mmol/L (target 0.6–0.8); toxicity ≥1.5 (coarse tremor, ataxia, vomiting, diarrhoea, confusion, seizures, renal failure)',
      'Toxicity precipitants: dehydration, NSAIDs, ACE inhibitors/ARBs, thiazides, low sodium, infection, renal impairment, drug interactions',
      'Long-term effects: hypothyroidism, hyperparathyroidism/hypercalcaemia, nephrogenic diabetes insipidus, chronic kidney disease'],
    management:[
      'Diagnosis and initiation are specialist; primary care provides shared-care monitoring, relapse vigilance and physical-health care',
      'Check lithium level 12 hours post-dose: weekly after starting/any dose change until stable, then every 3 months (6-monthly if very stable, per local protocol)',
      'Monitor U&E/eGFR, TFTs and calcium at baseline and every 6 months; weight/BMI and ECG where indicated',
      'Give every patient a lithium record book/alert card; counsel on consistent fluid/salt intake, signs of toxicity, and avoiding NSAIDs',
      'Never stop lithium abruptly (rebound mania) — reduce gradually over at least 4 weeks if stopping',
      'Avoid sodium valproate in women of childbearing potential; bipolar in pregnancy needs specialist perinatal input (lithium teratogenicity vs relapse risk)',
      'Manage acute relapse with prompt specialist contact; screen for suicidality at every review'],
    referral:[
      'Acute mania, severe depression, psychosis or significant suicide risk → urgent/same-day mental-health assessment',
      'Lithium level ≥1.5 mmol/L or features of toxicity → withhold dose and arrange emergency assessment',
      'Pregnancy or pregnancy planning on a mood stabiliser → perinatal mental-health service',
      'Rising creatinine, thyroid or calcium abnormality → discuss with mental-health team ± relevant specialty'],
    source:'NICE CG185 / NICE CKS' },

  { id:'diabetic-foot', title:'Diabetic foot disease', category:'Endocrine & metabolic', icon:'🦶',
    overview:'Foot complications of diabetes arising from peripheral neuropathy and/or peripheral arterial disease, leading to ulceration, infection, Charcot arthropathy and amputation. It is a leading cause of lower-limb amputation, and most amputations are preventable with structured risk assessment and rapid referral.',
    features:[
      'Neuropathy: loss of protective sensation (10 g monofilament), numbness/tingling/burning, dry skin, clawing, callus over pressure points',
      'Ischaemia: absent foot pulses, cold pale foot, rest pain, delayed capillary refill, hair loss, claudication',
      'Active ulcer: break in skin (often painless and over a pressure area); assess size, depth, base and infection',
      'Infection: spreading erythema, warmth, swelling, discharge, malodour, systemic upset — may be subtle in neuropathy',
      'Charcot arthropathy: a red, hot, swollen foot (often unilateral, ±deformity) with intact skin in a neuropathic patient — frequently misdiagnosed as cellulitis/gout/DVT'],
    management:[
      'Annual foot check for every person with diabetes: inspection, 10 g monofilament, pulses — then stratify risk (low / moderate / high / active problem)',
      'Low risk: foot-care education and continue annual review; moderate/high risk: refer to the foot protection service and review more frequently',
      'Optimise the basics — glycaemic control, blood pressure, lipids/statin, smoking cessation, and well-fitting footwear/offloading',
      'Active ulcer or suspected infection: refer to the multidisciplinary foot service within 24 hours; start antibiotics for clinical infection per local guidance and take a deep-tissue/swab sample',
      'Suspected Charcot: immediate referral and non-weight-bearing/immobilisation — do not wait',
      'Provide clear safety-netting: seek same-day help for new ulceration, colour change, swelling, increasing pain or systemic symptoms'],
    referral:[
      'Active ulcer, infection, gangrene or unexplained hot swollen foot → multidisciplinary diabetic foot service within 24 hours (same-day if limb-threatening or systemically unwell)',
      'Critical limb ischaemia (rest pain, tissue loss) → urgent vascular',
      'Suspected Charcot arthropathy → immediate foot service referral and offloading',
      'Moderate/high risk feet → foot protection service for ongoing surveillance'],
    source:'NICE NG19 (Diabetic foot problems)' },

  { id:'eating-disorders', title:'Eating disorders (anorexia & bulimia nervosa)', category:'Mental health', icon:'🍽️',
    overview:'Serious mental-health disorders characterised by disturbed eating behaviour and over-valuation of weight/shape. Anorexia nervosa has the highest mortality of any psychiatric illness (starvation and suicide). Early recognition and prompt referral substantially improve outcomes; physical risk can be life-threatening even at a "normal" weight.',
    features:[
      'Anorexia nervosa: restricted intake, low weight, intense fear of weight gain, body-image distortion; amenorrhoea, cold intolerance, lanugo, bradycardia, hypotension',
      'Bulimia nervosa: recurrent binge eating with compensatory behaviours (vomiting, laxatives, fasting, exercise); often normal weight; parotid swelling, dental erosion, Russell sign, hypokalaemia',
      'Screen with SCOFF (≥2 positive is significant); ask sensitively about bingeing, purging, laxative/diuretic and exercise behaviours',
      'Markers of medical instability (MEED): BMI very low or rapid weight loss, bradycardia <40, hypotension/postural drop, hypoglycaemia, hypokalaemia/hyponatraemia/hypophosphataemia, prolonged QTc, proximal myopathy (sit-up–squat–stand test)',
      'High comorbidity with depression, anxiety, OCD, self-harm, substance misuse, and type 1 diabetes (insulin omission)'],
    management:[
      'Take a positive, non-judgemental stance; the role of primary care is risk assessment, physical monitoring and rapid referral, not "wait and watch"',
      'Refer everyone with a suspected eating disorder to a community eating-disorder service immediately — do not use BMI thresholds as the sole basis for referral',
      'Assess physical risk now: weight/BMI and trend, lying/standing pulse and BP, bloods (FBC, U&E, phosphate, magnesium, glucose, LFTs), ECG for QTc',
      'Monitor at agreed intervals; be alert to refeeding syndrome (falling phosphate/magnesium/potassium) when nutrition is reintroduced',
      'Manage comorbid depression/anxiety, but in anorexia weight restoration takes priority and antidepressants are largely ineffective at low weight',
      'Involve family/carers (especially for children and young people) and provide carer support; safeguarding where a child is at risk'],
    referral:[
      'All suspected eating disorders → community eating-disorder service (urgent if rapidly deteriorating)',
      'Medical instability (MEED high-risk: e.g. bradycardia, hypotension, electrolyte disturbance, prolonged QTc, BMI critically low) → urgent medical admission',
      'Significant suicide/self-harm risk → urgent mental-health assessment',
      'Type 1 diabetes with insulin omission → joint diabetes + eating-disorder input'],
    source:'NICE NG69 / MEED guidance (RCPsych CR233, 2022)' },

  { id:'epilepsy', title:'Epilepsy', category:'Neurology', icon:'🧠',
    overview:'A tendency to recurrent unprovoked seizures. Diagnosis is clinical and specialist; the primary-care role centres on safe first-seizure referral, anti-seizure medication monitoring, women’s and pregnancy issues, driving advice and SUDEP awareness.',
    features:[
      'Focal seizures (with/without impaired awareness; may generalise) vs generalised seizures (tonic-clonic, absence, myoclonic, atonic)',
      'Take a careful eyewitness history: aura, focal onset, tongue-biting (lateral), incontinence, post-ictal confusion/drowsiness, duration',
      'Distinguish from syncope (situational, rapid recovery), non-epileptic attack disorder and other transient events',
      'Identify provoking factors (alcohol/drug withdrawal, sleep deprivation, metabolic) — provoked seizures are not epilepsy',
      'Status epilepticus (seizure >5 minutes or repeated without recovery) is a medical emergency'],
    management:[
      'First unprovoked seizure: refer to a first-seizure clinic to be seen within 2 weeks; do not usually start anti-seizure medication in primary care',
      'Anti-seizure choice is specialist-led: lamotrigine or levetiracetam are common first-line for focal and for generalised tonic-clonic seizures; ethosuximide for absence',
      'Sodium valproate must not be used in women/girls of childbearing potential unless the Pregnancy Prevention Programme conditions are met (high teratogenicity/neurodevelopmental risk)',
      'Women planning pregnancy: prescribe folic acid 5 mg daily, optimise to the lowest effective dose of the safest drug, and never stop medication abruptly — refer for specialist pre-conception advice',
      'Counsel on driving: must stop driving and inform the DVLA — typically 6 months seizure-free after a first seizure, 12 months for established epilepsy (group 1)',
      'Discuss SUDEP, seizure first aid, safety (baths/showers, heights, swimming) and medication adherence; review at least annually',
      'Provide rescue medication (buccal midazolam) plans for prolonged/cluster seizures where indicated'],
    referral:[
      'First seizure or suspected new epilepsy → urgent neurology/first-seizure clinic (within 2 weeks)',
      'Status epilepticus or a seizure not stopping → 999/emergency',
      'Pregnancy or pregnancy planning → specialist epilepsy/obstetric pre-conception input',
      'Poor seizure control, adverse effects, or considering withdrawal of medication → neurology'],
    source:'NICE NG217 / MHRA valproate safety guidance' },

  { id:'red-s', title:'Relative energy deficiency in sport (female athlete triad)', category:'Endocrine & metabolic', icon:'🏃',
    overview:'A syndrome of impaired physiological function caused by low energy availability — insufficient dietary energy for both training and bodily function. The classic female athlete triad is low energy availability, menstrual dysfunction and low bone mineral density; the broader RED-S concept also affects males and multiple systems.',
    features:[
      'Low energy availability: intentional restriction, high training load, disordered eating, or simply under-fuelling',
      'Menstrual dysfunction: functional hypothalamic amenorrhoea or oligomenorrhoea (exclude pregnancy, thyroid and hyperprolactinaemia)',
      'Impaired bone health: recurrent/stress fractures, low bone mineral density for age',
      'Other RED-S effects: fatigue, recurrent illness/injury, poor performance, mood disturbance, GI and cardiovascular effects',
      'At-risk groups: endurance, aesthetic and weight-category sports; be alert in any athletic young person with stress fractures or amenorrhoea'],
    management:[
      'Recognise the link between under-fuelling, lost periods and stress fractures — do not simply attribute amenorrhoea to "being athletic"',
      'Increase energy availability: dietitian input to raise energy intake and/or reduce training load — this is the core treatment',
      'Investigate amenorrhoea appropriately (exclude pregnancy, check TFTs, prolactin, FSH/LH/oestradiol) and assess bone health (DEXA) where indicated',
      'The combined oral contraceptive masks menstrual recovery and does not reliably restore bone density — restoring energy balance and weight is the priority',
      'Ensure adequate calcium and vitamin D; screen for and treat a co-existing eating disorder',
      'Multidisciplinary approach: athlete, coach, dietitian, sports physician ± psychology'],
    referral:[
      'Recurrent stress fractures, significantly low bone density, or persistent amenorrhoea → sports medicine / endocrinology',
      'Suspected eating disorder → community eating-disorder service',
      'Diagnostic uncertainty about the cause of amenorrhoea → gynaecology/endocrinology'],
    source:'IOC RED-S consensus / BASEM' }

  );
})();
